"""Structured logging module with log levels."""
import json
import sys
from datetime import datetime


def _emit(level, message):
    entry = {"timestamp": datetime.now().isoformat(), "level": level, "message": message}
    print(json.dumps(entry), file=sys.stderr)


def debug(message):
    _emit("DEBUG", message)


def info(message):
    _emit("INFO", message)


def warn(message):
    _emit("WARN", message)


def error(message):
    _emit("ERROR", message)

